class Solution:
    def smallestFromLeaf(self, root):
        candidates = []
        def dfs(node, suffix):
            if node is None:
                return
            s = chr(node.val + 97) + suffix
            if node.left is None and node.right is None:
                candidates.append(s)
                return
            dfs(node.left, s)
            dfs(node.right, s)
        dfs(root, '')
        return min(candidates)

