class Solution:
    def smallestFromLeaf(self, root):
        best = [None]
        def dfs(node, path):
            if node is None:
                return
            path.append(chr(node.val + 97))
            if node.left is None and node.right is None:
                cand = ''.join(reversed(path))
                if best[0] is None or cand < best[0]:
                    best[0] = cand
            else:
                dfs(node.left, path)
                dfs(node.right, path)
            path.pop()
        dfs(root, [])
        return best[0]

