var smallestFromLeaf = function(root) {
    let best = null;
    const dfs = (node, path) => {
        if (node === null) return;
        path.push(String.fromCharCode(node.val + 97));
        if (node.left === null && node.right === null) {
            const cand = path.slice().reverse().join('');
            if (best === null || cand < best) best = cand;
        } else {
            dfs(node.left, path);
            dfs(node.right, path);
        }
        path.pop();
    };
    dfs(root, []);
    return best;
};
